        ["algo" => 762, "uuid" => "ed6db9", "name" => "ibe", "type" => "advanced", "status" => "new", "title" => "IBE", "description_md" => "IBE (Identity-Based Encryption, Boneh-Franklin 2001) allows encrypting to an arbitrary identity string (email, user ID) without pre-distributing public keys. A PKG (Private Key Generator) issues private keys.\n\nIBE uses bilinear pairings on elliptic curves. Used in enterprise email encryption and some IoT proposals. Voltage Security (now HPE) deployed IBE commercially.", "mental_model" => "Encrypt to identity string -- IBE, no pubkey needed, PKG issues keys, Boneh-Franklin.", "purpose" => ["encryption to arbitrary identity (no pubkey)"], "good_for" => ["email encryption without pubkey exchange", "iot identity-based keys", "enterprise key management simplification"], "avoid_for" => ["decentralized (PKG is trusted third party)", "production web (use standard PKI)"], "pros" => ["no pubkey pre-distribution", "natural identity binding", "pairing-based standard"], "cons" => ["PKG knows all private keys", "bilinear pairing overhead", "PKG trust required"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Bilinear pairings; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Email IBE encryption", "input" => ["to" => "alice@example.com", "msg" => "secret"], "output" => ["ciphertext" => "IBE-encrypted to identity"]], "flow" => ["PKG setup: master key", "encryption: E(identity, msg)", "key extraction: PKG issues d_ID to user", "decryption with d_ID"], "related" => ["abe", "pre", "functional-encryption"]],
        ["algo" => 763, "uuid" => "e3ff73", "name" => "abe", "type" => "advanced", "status" => "new", "title" => "ABE", "description_md" => "ABE (Attribute-Based Encryption) generalizes IBE to policies. In KP-ABE (key-policy), decryption keys encode access policies; ciphertexts are tagged with attributes. In CP-ABE (ciphertext-policy), the ciphertext encodes the policy.\n\nABE is used for fine-grained access control without key distribution, cloud storage access control, and health records encryption.", "mental_model" => "Policy-based encryption -- ABE, decrypt iff attributes satisfy policy, CP-ABE/KP-ABE.", "purpose" => ["attribute/policy-based encryption for access control"], "good_for" => ["cloud storage fine-grained access", "health records (encrypt to policy)", "iot access control"], "avoid_for" => ["simple point-to-point (use RSA/ECDH)", "performance-sensitive (pairing overhead)"], "pros" => ["fine-grained access control", "no key distribution per policy", "expressive policies"], "cons" => ["pairing overhead", "complex", "trusted authority"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Bilinear pairings; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Cloud storage CP-ABE", "input" => ["policy" => "dept=HR AND role=manager", "data" => "file"], "output" => ["ciphertext" => "CP-ABE encrypted"]], "flow" => ["setup authority + master key", "encrypt with CP-ABE policy", "issue key with attributes", "decrypt if attributes satisfy policy"], "related" => ["ibe", "functional-encryption", "pre"]],
        ["algo" => 764, "uuid" => "3f6e6c", "name" => "pre", "type" => "advanced", "status" => "new", "title" => "Proxy Re-Encryption", "description_md" => "PRE (Proxy Re-Encryption) allows a semi-trusted proxy to transform ciphertext encrypted under Alice's key so that Bob can decrypt it, without the proxy learning the plaintext.\n\nPRE is used in encrypted storage delegation, key rotation, and confidential computing handoff.", "mental_model" => "Delegate decryption via proxy -- PRE, transform ciphertext A->B, proxy learns nothing.", "purpose" => ["ciphertext re-encryption delegation without plaintext"], "good_for" => ["encrypted storage delegation", "key rotation", "cloud data sharing", "email forwarding"], "avoid_for" => ["simple key exchange (dhkm)", "proxy not semi-trusted"], "pros" => ["proxy cannot decrypt", "delegation without key sharing", "key rotation efficient"], "cons" => ["semi-trusted proxy required", "complex"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Usually pairing-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Cloud storage delegation", "input" => ["ctxt_alice" => "enc(Alice)", "rk" => "re-key A->B"], "output" => ["ctxt_bob" => "transformed for Bob"]], "flow" => ["keygen(Alice, Bob) -> re-key rk", "proxy: ReEnc(ctxt_alice, rk) -> ctxt_bob", "Bob decrypts ctxt_bob with his key"], "related" => ["ibe", "abe", "functional-encryption"]],
